<template><view class="page"><view class="head"><text class="back" @tap="back">‹</text><text class="title">情侣空间</text><text class="rank" @tap="showRank=true">榜单</text></view>
<view class="bind" v-if="!space"><view class="heart">♥</view><text class="bind-title">把一日三餐，变成两个人的事</text><text class="bind-desc">创建空间后把邀请码分享给对方，绑定后双方都可以点菜和异地投喂</text><picker mode="date" :value="startDate" @change="startDate=$event.detail.value"><view class="date-input">相恋日期：{{startDate}}</view></picker><view class="primary" @tap="create">创建情侣空间</view><view class="or">已有邀请码</view><view class="join"><input v-model="inviteCode" maxlength="6" placeholder="输入6位邀请码"/><text @tap="join">绑定</text></view></view>
<scroll-view class="body" scroll-y v-else><view class="love-card"><text class="days">{{days}}</text><text class="days-label">我们在一起的天数</text><view class="couple"><view><image src="/static/kitchen_avatar.png"/><text>我</text></view><text class="line">♥</text><view><image src="/static/kitchen_avatar.png"/><text>{{space.userB?'TA':'等待绑定'}}</text></view></view><view class="invite" v-if="!space.userB">邀请码 {{space.inviteCode}} <button open-type="share">邀请 TA</button></view></view>
<view class="actions"><view @tap="goFeed"><text class="action-icon">投</text><text>异地投喂</text><small>给对方远程下单</small></view><view @tap="goOrder"><text class="action-icon">菜</text><text>一起点菜</text><small>双方都能操作</small></view><view @tap="showRank=true"><text class="action-icon">榜</text><text>情侣榜单</text><small>看看甜蜜排行</small></view></view>
<view class="section-row"><text>我们的纪念日</text><text @tap="showAdd=true">＋ 添加</text></view><view class="ann-list"><view class="ann" v-for="a in (space.anniversaries||[])" :key="a.id"><view class="calendar">{{String(a.anniversaryDate).slice(5)}}</view><view><text>{{a.title}}</text><text>每一个日子都值得记住</text></view></view><view class="empty" v-if="!(space.anniversaries||[]).length">还没有添加纪念日</view></view><view class="feed-stat">已经为彼此投喂 <b>{{space.feedCount||0}}</b> 次</view></scroll-view>
<view class="mask" v-if="showAdd||showRank" @tap="showAdd=false;showRank=false"></view><view class="sheet" v-if="showAdd"><text class="sheet-title">添加纪念日</text><input v-model="annTitle" placeholder="纪念日名称"/><picker mode="date" :value="annDate" @change="annDate=$event.detail.value"><view class="date-input">{{annDate}}</view></picker><view class="primary" @tap="addAnn">保存</view></view><view class="sheet rank-sheet" v-if="showRank"><text class="sheet-title">情侣投喂榜</text><view class="rank-row" v-for="(r,i) in leaderboard" :key="r.id"><text>{{i+1}}</text><text>{{r.userAName}} ♥ {{r.userBName}}</text><text>{{r.feedCount}}次</text></view><view class="empty" v-if="!leaderboard.length">还没有榜单数据</view></view></view></template>
<script>import{apiCoupleCreate,apiCoupleJoin,apiCoupleDetail,apiCoupleAnniversary,apiCoupleLeaderboard}from'@/api/social.js';import{ensureLogin}from'@/utils/login.js';export default{data(){let d=new Date().toISOString().slice(0,10);return{space:null,startDate:d,inviteCode:'',showAdd:false,annTitle:'',annDate:d,showRank:false,leaderboard:[]}},computed:{days(){if(!this.space)return 0;return Math.max(1,Math.floor((Date.now()-new Date(this.space.startDate).getTime())/86400000)+1)}},onLoad(o){if(o.code)this.inviteCode=o.code;this.load();this.loadRank()},onShareAppMessage(){return{title:'邀请你绑定我们的情侣空间',path:'/pages/couple-space/couple-space?code='+(this.space?this.space.inviteCode:'')}},methods:{async load(){try{await ensureLogin();let r=await apiCoupleDetail();this.space=r.data;if(!this.space&&this.inviteCode)this.join()}catch(e){}},async create(){try{let r=await apiCoupleCreate({startDate:this.startDate});this.space=r.data;await this.load()}catch(e){}},async join(){if(!this.inviteCode)return;try{await apiCoupleJoin({inviteCode:this.inviteCode});await this.load();uni.showToast({title:'绑定成功',icon:'success'})}catch(e){}},async addAnn(){if(!this.annTitle.trim())return;await apiCoupleAnniversary({title:this.annTitle,anniversaryDate:this.annDate});this.showAdd=false;this.annTitle='';await this.load()},goOrder(){uni.reLaunch({url:'/pages/index/index'})},goFeed(){if(!this.space.userB){uni.showToast({title:'请先邀请对方完成绑定',icon:'none'});return}uni.setStorageSync('coupleRemoteFeed','1');uni.reLaunch({url:'/pages/index/index'});},async loadRank(){try{let r=await apiCoupleLeaderboard();this.leaderboard=r.data||[]}catch(e){}},back(){uni.navigateBack()}}}</script>
<style>.page{min-height:100vh;background:#fff7f7;color:#31282a}.head{height:166rpx;padding:calc(34rpx + env(safe-area-inset-top)) 28rpx 22rpx;display:flex;align-items:flex-end;background:linear-gradient(135deg,#ffe3e8,#fff8f5);box-sizing:border-box}.back{width:62rpx;font-size:54rpx}.title{flex:1;font-size:38rpx;font-weight:900}.rank{color:#e86f86;font-weight:800}.bind{padding:44rpx 30rpx;display:flex;flex-direction:column;align-items:center}.heart{width:120rpx;height:120rpx;border-radius:40rpx;background:#ffebef;color:#ed7188;text-align:center;line-height:120rpx;font-size:58rpx}.bind-title{margin-top:28rpx;font-size:34rpx;font-weight:900}.bind-desc{margin:14rpx 20rpx 28rpx;text-align:center;font-size:24rpx;line-height:1.6;color:#917d82}.date-input{height:78rpx;padding:0 24rpx;border-radius:16rpx;background:#fff;display:flex;align-items:center;box-sizing:border-box;color:#796b6e}.bind picker{width:100%}.primary{width:100%;height:82rpx;margin-top:18rpx;border-radius:42rpx;background:#ef7e93;color:#fff;display:flex;align-items:center;justify-content:center;font-size:29rpx;font-weight:900}.or{margin:30rpx;color:#a79599}.join{width:100%;height:80rpx;padding:0 22rpx;border-radius:16rpx;background:#fff;display:flex;align-items:center;box-sizing:border-box}.join input{flex:1}.join text{color:#e86f86;font-weight:900}.body{height:calc(100vh - 166rpx)}.love-card{margin:24rpx;padding:34rpx;border-radius:30rpx;background:linear-gradient(145deg,#ef7e93,#f4a4a5);color:#fff;text-align:center;box-shadow:0 14rpx 30rpx rgba(220,95,119,.2)}.days{display:block;font-size:72rpx;font-weight:900}.days-label{font-size:23rpx;opacity:.86}.couple{margin-top:28rpx;display:flex;align-items:center;justify-content:center;gap:26rpx}.couple view{display:flex;flex-direction:column}.couple image{width:84rpx;height:84rpx;border-radius:50%;border:4rpx solid rgba(255,255,255,.7)}.couple view text{margin-top:7rpx}.line{font-size:36rpx}.invite{margin-top:20rpx}.invite button{display:inline-block;margin-left:12rpx;padding:0 18rpx;height:50rpx;line-height:50rpx;border-radius:25rpx;font-size:21rpx}.actions{margin:0 24rpx;display:grid;grid-template-columns:repeat(3,1fr);gap:12rpx}.actions>view{padding:22rpx 8rpx;border-radius:20rpx;background:#fff;display:flex;flex-direction:column;align-items:center}.action-icon{width:58rpx;height:58rpx;border-radius:20rpx;background:#fff0f2;color:#e86f86;text-align:center;line-height:58rpx;font-weight:900}.actions>view>text:nth-child(2){margin-top:10rpx;font-weight:900}.actions small{margin-top:5rpx;font-size:18rpx;color:#a18e92}.section-row{padding:34rpx 30rpx 16rpx;display:flex;justify-content:space-between;font-size:29rpx;font-weight:900}.section-row text:last-child{font-size:23rpx;color:#e86f86}.ann-list{margin:0 24rpx;border-radius:22rpx;background:#fff;overflow:hidden}.ann{padding:20rpx;display:flex;align-items:center;border-bottom:1rpx solid #f4e9eb}.calendar{width:82rpx;height:70rpx;border-radius:15rpx;background:#fff0f2;color:#e86f86;text-align:center;line-height:70rpx;font-weight:900}.ann>view:last-child{margin-left:16rpx;display:flex;flex-direction:column}.ann>view:last-child text:first-child{font-weight:900}.ann>view:last-child text:last-child{margin-top:7rpx;font-size:21rpx;color:#a28f93}.empty{padding:45rpx;text-align:center;color:#a89599}.feed-stat{margin:22rpx 24rpx 70rpx;text-align:center;color:#9b888c}.feed-stat b{color:#e86f86}.mask{position:fixed;inset:0;background:rgba(40,30,33,.45);z-index:20}.sheet{position:fixed;left:0;right:0;bottom:0;z-index:21;padding:30rpx 28rpx calc(30rpx + env(safe-area-inset-bottom));border-radius:28rpx 28rpx 0 0;background:#fff}.sheet-title{display:block;font-size:33rpx;font-weight:900;margin-bottom:20rpx}.sheet input{height:78rpx;padding:0 22rpx;background:#faf3f4;border-radius:16rpx;margin-bottom:14rpx}.rank-row{height:76rpx;display:grid;grid-template-columns:50rpx 1fr 80rpx;align-items:center;border-bottom:1rpx solid #f2e8ea}.rank-row text:last-child{color:#e86f86;text-align:right}.rank-sheet{max-height:70vh;overflow:auto}</style>
